import javax.jws.WebService;
import javax.jws.WebMethod;
import javax.xml.soap.SOAPMessage;
import javax.xml.soap.SOAPException;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;
import org.w3c.dom.Document;
import org.xml.sax.SAXException;
import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.StringWriter;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebService
public class XmlProcessingService {

    private static final Logger logger = Logger.getLogger(XmlProcessingService.class.getName());

    @WebMethod
    public String processXml(SOAPMessage soapMessage) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            factory.setValidating(false);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/validation", false);

            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new ByteArrayInputStream(soapMessage.getSOAPBody().getTextContent().getBytes()));

            // Process the XML document
            String result = processDocument(document);

            return result;

        } catch (SOAPException | ParserConfigurationException | SAXException | IOException e) {
            logger.log(Level.SEVERE, "Error processing SOAP message", e);
            return "Error processing request";
        }
    }

    private String processDocument(Document document) {
        // Implement your logic to handle complex XML structures and nested entities here
        // For demonstration, we will just convert the Document back to a String

        try {
            TransformerFactory transformerFactory = TransformerFactory.newInstance();
            Transformer transformer = transformerFactory.newTransformer();
            DOMSource source = new DOMSource(document);
            StringWriter writer = new StringWriter();
            StreamResult result = new StreamResult(writer);
            transformer.transform(source, result);
            return writer.toString();
        } catch (Exception e) {
            logger.log(Level.SEVERE, "Error transforming document", e);
            return "Error processing document";
        }
    }
}